import { Component, OnInit } from '@angular/core';
import { RoomService } from '../../services/room.service';
import { Room } from '../../models/room.model';

@Component({
  selector: 'app-rooms',
  templateUrl: './rooms.component.html',
  styleUrls: ['./rooms.component.css']
})
export class RoomsComponent implements OnInit {
  rooms: Room[] = [];
  loading = true;
  newRoom: Room = { roomNumber: '', roomType: 'SINGLE', totalBeds: 1, occupiedBeds: 0, floor: '', available: true };
  showForm = false;

  constructor(private roomService: RoomService) {}

  ngOnInit() {
    this.loadRooms();
  }

  loadRooms() {
    this.roomService.getAllRooms().subscribe({
      next: (data) => { this.rooms = data; this.loading = false; },
      error: (error) => { console.error(error); this.loading = false; }
    });
  }

  createRoom() {
    this.roomService.createRoom(this.newRoom).subscribe({
      next: () => { this.loadRooms(); this.showForm = false; this.resetForm(); alert('Room created successfully!'); },
      error: (error) => alert('Error creating room')
    });
  }

  deleteRoom(id: number) {
    if(confirm('Delete this room?')) {
      this.roomService.deleteRoom(id).subscribe({
        next: () => { this.loadRooms(); alert('Room deleted!'); },
        error: (error) => alert('Error deleting room')
      });
    }
  }

  resetForm() {
    this.newRoom = { roomNumber: '', roomType: 'SINGLE', totalBeds: 1, occupiedBeds: 0, floor: '', available: true };
  }
}
<div class="content-wrapper">
  <div class="container-fluid">
    <div class="d-flex justify-content-between align-items-center mb-4">
      <h2>Room Management</h2>
      <button class="btn btn-primary" (click)="showForm = !showForm">{{ showForm ? 'Cancel' : '+ Add Room' }}</button>
    </div>

    <div *ngIf="showForm" class="card mb-4">
      <div class="card-body">
        <h5>Add New Room</h5>
        <form (ngSubmit)="createRoom()">
          <div class="row">
            <div class="col-md-3 mb-3">
              <label class="form-label">Room Number</label>
              <input type="text" class="form-control" [(ngModel)]="newRoom.roomNumber" name="roomNumber" required>
            </div>
            <div class="col-md-3 mb-3">
              <label class="form-label">Room Type</label>
              <select class="form-control" [(ngModel)]="newRoom.roomType" name="roomType">
                <option value="SINGLE">Single</option>
                <option value="DOUBLE">Double</option>
                <option value="TRIPLE">Triple</option>
                <option value="FOUR_SHARING">Four Sharing</option>
              </select>
            </div>
            <div class="col-md-2 mb-3">
              <label class="form-label">Total Beds</label>
              <input type="number" class="form-control" [(ngModel)]="newRoom.totalBeds" name="totalBeds" required>
            </div>
            <div class="col-md-2 mb-3">
              <label class="form-label">Floor</label>
              <input type="text" class="form-control" [(ngModel)]="newRoom.floor" name="floor" required>
            </div>
            <div class="col-md-2 mb-3">
              <label class="form-label">&nbsp;</label>
              <button type="submit" class="btn btn-success w-100">Create Room</button>
            </div>
          </div>
        </form>
      </div>
    </div>

    <div class="table-responsive">
      <table class="table table-striped">
        <thead>
          <tr>
            <th>Room Number</th>
            <th>Type</th>
            <th>Total Beds</th>
            <th>Occupied</th>
            <th>Available</th>
            <th>Floor</th>
            <th>Status</th>
            <th>Actions</th>
          </tr>
        </thead>
        <tbody>
          <tr *ngFor="let room of rooms">
            <td>{{ room.roomNumber }}</td>
            <td>{{ room.roomType }}</td>
            <td>{{ room.totalBeds }}</td>
            <td>{{ room.occupiedBeds }}</td>
            <td>{{ room.totalBeds - room.occupiedBeds }}</td>
            <td>{{ room.floor }}</td>
            <td><span [class]="room.available ? 'badge bg-success' : 'badge bg-danger'">
              {{ room.available ? 'Available' : 'Full' }}</span></td>
            <td><button class="btn btn-sm btn-danger" (click)="deleteRoom(room.id!)">Delete</button></td>
          </tr>
        </tbody>
      </table>
    </div>
  </div>
</div>
